import{_ as t,o as a,c as i,a0 as n}from"./chunks/framework.jwovEGr5.js";const p=JSON.parse('{"title":"Direct Alliance Subscriptions","description":"","frontmatter":{},"headers":[],"relativePath":"subscriptions/direct-alliance-subscription.md","filePath":"subscriptions/direct-alliance-subscription.md"}'),s={name:"subscriptions/direct-alliance-subscription.md"};function r(o,e,l,d,h,c){return a(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="direct-alliance-subscriptions" tabindex="-1">Direct Alliance Subscriptions <a class="header-anchor" href="#direct-alliance-subscriptions" aria-label="Permalink to &quot;Direct Alliance Subscriptions&quot;">​</a></h1><p>An alliance can get premium two ways: through a <a href="./kingdom-grants.html">grant</a> from its King, or by having its <strong>own</strong> subscription — a <strong>direct alliance subscription</strong>. This page explains the &quot;own plan&quot; route and why an alliance might prefer it.</p><h2 id="what-direct-means" tabindex="-1">What &quot;direct&quot; means <a class="header-anchor" href="#what-direct-means" aria-label="Permalink to &quot;What &quot;direct&quot; means&quot;">​</a></h2><p>A direct alliance subscription is a <a href="./../getting-started/glossary.html#plan">plan</a> that belongs to the <strong>alliance itself</strong>, not borrowed from the kingdom. On your usage panel, its <strong>plan source</strong> reads <strong>&quot;Direct alliance plan&quot;</strong> — the strongest source in the <a href="./effective-plan.html">effective-plan order</a>.</p><p>You get one the same way as any premium plan: <a href="./request-subscription.html">request it</a> and arrange <a href="./payment-instructions.html">payment</a> with a Supreme Admin.</p><h2 id="direct-plan-vs-kingdom-grant" tabindex="-1">Direct plan vs. kingdom grant <a class="header-anchor" href="#direct-plan-vs-kingdom-grant" aria-label="Permalink to &quot;Direct plan vs. kingdom grant&quot;">​</a></h2><p>Both give an alliance premium, but they behave differently:</p><table tabindex="0"><thead><tr><th></th><th>Direct alliance plan</th><th>Accepted kingdom grant</th></tr></thead><tbody><tr><td>Belongs to</td><td>The alliance</td><td>The kingdom (shared with you)</td></tr><tr><td>How you get it</td><td>Request + arrange payment yourself</td><td>Your King offers it; you accept</td></tr><tr><td>Features</td><td>The full alliance premium set</td><td>Only the <strong>shareable</strong> features the grant carries</td></tr><tr><td>If the King changes plans</td><td>Unaffected — it&#39;s yours</td><td>Can end if the King revokes the grant</td></tr><tr><td>Survives a kingdom <strong>usage-limit</strong> pause</td><td><strong>Yes</strong></td><td>No (unless separately exempted)</td></tr></tbody></table><h2 id="the-big-advantage-surviving-a-kingdom-usage-limit-suspension" tabindex="-1">The big advantage: surviving a kingdom usage-limit suspension <a class="header-anchor" href="#the-big-advantage-surviving-a-kingdom-usage-limit-suspension" aria-label="Permalink to &quot;The big advantage: surviving a kingdom usage-limit suspension&quot;">​</a></h2><p>If the <strong>kingdom</strong> hits a hard limit and drops into a usage-limit <a href="./suspension.html">suspension</a>, alliances under it are normally paused too — <strong>except</strong> an alliance with its <strong>own direct paid plan, which keeps working</strong>. Its own subscription shields it from the kingdom&#39;s usage-limit pause.</p><p>This is the main reason an alliance that wants reliable, independent premium — not tied to the kingdom&#39;s ups and downs — chooses a direct subscription.</p><blockquote><p>This shield applies specifically to <strong>usage-limit</strong> kingdom suspensions. The harder administrative reasons (manual, admin, abuse, global) can still cascade unless a Supreme Admin grants a specific override. See the cascade rules in <a href="./suspension.html">Suspension &amp; Limited Mode</a>.</p></blockquote><h2 id="which-should-an-alliance-choose" tabindex="-1">Which should an alliance choose? <a class="header-anchor" href="#which-should-an-alliance-choose" aria-label="Permalink to &quot;Which should an alliance choose?&quot;">​</a></h2><ul><li><strong>Choose a grant</strong> if your King is happy to share the kingdom&#39;s premium and you&#39;re fine depending on it. It&#39;s the no-cost-to-you route — see <a href="./accept-grant.html">Accept a Premium Offer</a>.</li><li><strong>Choose a direct plan</strong> if you want the full alliance feature set, independence from the kingdom&#39;s plan, and protection from a kingdom usage-limit pause.</li></ul><p>There&#39;s no wrong answer — it depends on how independent your alliance wants to be.</p><h2 id="where-to-go-next" tabindex="-1">Where to go next <a class="header-anchor" href="#where-to-go-next" aria-label="Permalink to &quot;Where to go next&quot;">​</a></h2><ul><li><a href="./request-subscription.html">Request a Subscription</a> — how to get a direct plan.</li><li><a href="./effective-plan.html">Which Plan Applies to You</a> — where a direct plan sits in the order.</li><li><a href="./suspension.html">Suspension &amp; Limited Mode</a> — the survival rule in full.</li></ul>',17)])])}const g=t(s,[["render",r]]);export{p as __pageData,g as default};
